urlset:
{% for post in site.posts %}

    {{ site.url }}{{ post.url }}
    {% if post.lastmod %}
      {{ post.lastmod | date_to_xmlschema }}
    {% else %}
      {{ post.date | date_to_xmlschema }}
    {% endif %}
    monthly
    0.8

{% endfor %}

{% for page in site.pages %}
  {% if page.layout != nil and page.layout != 'none' and page.url != '/404.html' %}

      {{ site.url }}{{ page.url | remove: 'index.html' }}
      {% if page.date %}
        {{ page.date | date_to_xmlschema }}
      {% else %}
        {{ site.time | date_to_xmlschema }}
      {% endif %}
      weekly
      0.6

  {% endif %}
{% endfor %}
